<?php
namespace App\Livewire\Billing;
use App\Models\CashierSession; use App\Models\Invoice; use App\Models\Payment; use Illuminate\Support\Facades\Gate; use Livewire\Component;
class Dashboard extends Component { public function mount(): void { Gate::authorize('billing.view-dashboard'); } public function render(){ $f=currentFacility()?->id; return view('livewire.billing.dashboard',['stats'=>['pending'=>Invoice::where('facility_id',$f)->where('payment_status','unpaid')->count(),'partial'=>Invoice::where('facility_id',$f)->where('payment_status','partial')->count(),'paid_today'=>Invoice::where('facility_id',$f)->where('payment_status','paid')->whereDate('updated_at',today())->count(),'collected_today'=>Payment::where('facility_id',$f)->where('status','confirmed')->whereDate('payment_date',today())->sum('amount'),'outstanding'=>Invoice::where('facility_id',$f)->sum('balance_amount'),'active_sessions'=>CashierSession::where('facility_id',$f)->where('status','open')->count()],'recent'=>Payment::where('facility_id',$f)->with(['invoice.patient','method'])->latest()->limit(8)->get()])->layout('components.layouts.app',['title'=>'Billing Dashboard','description'=>'Muhtasari wa malipo, invoice na cashier sessions.']); } }
